SELECT object_id, title
FROM content_items
WHERE status = 'published';

SELECT content_type_id, icon_url
FROM content_types
WHERE icon_url IS NOT NULL;

SELECT content_type_name, description, TANH(content_type_id) AS tanh_content_type_id
FROM content_types
WHERE content_type_id = 1;

SELECT COUNT(*)
FROM content_items
WHERE status = 'published';

SELECT content_type_id, COUNT(object_id) as content_item_count
FROM content_items
GROUP BY content_type_id;

SELECT object_id, title, created_at
FROM content_items
ORDER BY created_at DESC;

SELECT object_id, object_repr
FROM content_items
WHERE parent_id NOT IN (SELECT user_id FROM users);
